#include<bits/stdc++.h>
using namespace std;
int n,k;
map<string,int>a;
string y,sum;
int main(){
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		string s;
		int x;
		cin>>s>>x;
		a[s]=x;
	}
	string su;
	getline(cin,su);
	for(int i=1;i<=k;i++){
		string sum;
		getline(cin,sum);
		for(int j=0;j<sum.length();j++){
			if(sum[j]=='{'){
				string ans="";
				int k=j+1;
				while(sum[k]!='}'){
					ans+=sum[k];
					k++;
				}
				if(a.find(ans)!=a.end())
					y+=a[ans]+'0';
				j=k;
			}
			else
				y+=sum[j];
		}
		cout<<y<<endl;
		y.clear();
	}
	return 0;
}
